// ── 图片资源（base64内嵌）──
const imgPS = new Image(); imgPS.src = 'data:image/png;base64,';
const imgZB = new Image(); imgZB.src = 'data:image/png;base64,';
const imgBG = new Image(); imgBG.src = 'data:image/jpeg;base64,';

// ── Socket.IO 连接（使用自定义路径）──
const socket = io('http://simon.nekko.cn:1234', { transports: ['polling'], timeout:60000, reconnectionDelay:1000, reconnectionAttempts:10 });

let myInfo=null, roomInfo=null, mySlotLocal=null, myHero=null, gameEngine=null;

const HEROES={
  peashooter:{name:'豌豆射手',desc:'远程·地雷·散弹闪',skills:['K-地雷','L-散弹+闪']},
  zombie:{name:'路障僵尸',desc:'近战·连击·冲刺',skills:['K-连续出拳','L-冲刺斩']}};

function showScreen(id){document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));document.getElementById('screen-'+id).classList.add('active');}
function showOverlay(msg){document.getElementById('overlay-txt').textContent=msg;document.getElementById('overlay-msg').classList.add('show');}
function hideOverlay(){document.getElementById('overlay-msg').classList.remove('show');}
function showMenu(){showScreen('menu');socket.emit('fight_get_leaderboard');}

function doLogin(){
  const key=document.getElementById('key-input').value.trim().toUpperCase();
  if(key.length<6){document.getElementById('login-err').textContent='密钥格式不正确';return;}
  document.getElementById('login-err').textContent='';
  socket.emit('fight_login',{key});
}
document.getElementById('key-input').addEventListener('keydown',e=>{if(e.key==='Enter')doLogin();});

socket.on('fight_login_ok',(data)=>{
  myInfo=data;
  document.getElementById('menu-player').textContent=`${data.name}  积分: ${data.score}  胜: ${data.wins}  负: ${data.losses}`;
  showMenu();
});
socket.on('fight_login_fail',({msg})=>{document.getElementById('login-err').textContent=msg;});

function startMatch(){
  if(!myInfo){showScreen('login');return;}
  document.getElementById('match-myname').textContent=myInfo.name;
  document.getElementById('match-myscore').textContent='积分: '+myInfo.score;
  myHero=null;
  showScreen('match');
  socket.emit('fight_find_match');
}
function cancelMatch(){socket.emit('fight_cancel_match');showMenu();}

socket.on('fight_waiting',()=>{
  document.getElementById('match-myname').textContent = myInfo.name;
  document.getElementById('match-myscore').textContent = '积分: ' + myInfo.score;
  showScreen('match');
});
socket.on('fight_room_ready',(data)=>{
  roomInfo=data;
  mySlotLocal=data.p1.key===myInfo.key?'p1':'p2';
  document.getElementById('select-banner').textContent=`${data.p1.name} VS ${data.p2.name}`;
  document.getElementById('opp1-name').textContent=data.p1.name;
  document.getElementById('opp2-name').textContent=data.p2.name;
  document.getElementById('opp1-hero').textContent='未选择';
  document.getElementById('opp2-hero').textContent='未选择';
  const grid=document.getElementById('heroes-grid');
  grid.innerHTML='';
  Object.entries(HEROES).forEach(([id,hero])=>{
    const card=document.createElement('div');
    card.className='hero-card';card.id='hcard-'+id;
    const cv=document.createElement('canvas');cv.width=100;cv.height=100;
    const cctx=cv.getContext('2d');
    const img=id==='peashooter'?imgPS:imgZB;
    const draw=()=>{cctx.clearRect(0,0,100,100);cctx.drawImage(img,id==='peashooter'?-10:-5,0,id==='peashooter'?115:110,105);};
    if(img.complete&&img.naturalWidth>0)draw(); else img.onload=draw;
    card.appendChild(cv);
    card.innerHTML+=`<div class="hname">${hero.name}</div><div class="hdesc">${hero.desc}</div>`;
    card.onclick=()=>selectHero(id);
    grid.appendChild(card);
  });
  document.getElementById('select-status').textContent='请选择你的英雄（30秒内）';
  _clearSelectTimeout();
  _selectTimeout=setTimeout(()=>{socket.emit('fight_cancel_match');showMenu();showOverlay('选角超时，已取消匹配');setTimeout(hideOverlay,2000);},30000);
  showScreen('select');
});

function selectHero(heroId){
  if(myHero)return;
  myHero=heroId;
  document.querySelectorAll('.hero-card').forEach(c=>c.classList.remove('selected'));
  document.getElementById('hcard-'+heroId).classList.add('selected');
  socket.emit('fight_select_hero',{hero:heroId});
  document.getElementById('select-status').innerHTML=`你选择了 <span>${HEROES[heroId].name}</span>，等待对手...`;
}
// 选角超时处理
let _selectTimeout = null;
function _clearSelectTimeout(){ if(_selectTimeout){clearTimeout(_selectTimeout);_selectTimeout=null;} }
socket.on('fight_hero_selected',({slot,hero})=>{
  document.getElementById(slot==='p1'?'opp1-hero':'opp2-hero').textContent=HEROES[hero]?.name||hero;
});

socket.on('fight_game_start',(data)=>{
  _clearSelectTimeout();
  const iAmP1=data.p1.key===myInfo.key;
  document.getElementById('p1name-hud').textContent=`${data.p1.name}(${HEROES[data.p1.hero]?.name||data.p1.hero})`;
  document.getElementById('p2name-hud').textContent=`${data.p2.name}(${HEROES[data.p2.hero]?.name||data.p2.hero})`;
  const h1=HEROES[data.p1.hero],h2=HEROES[data.p2.hero];
  if(h1){document.getElementById('sk1k-label').textContent=h1.skills[0].split('-')[0];document.getElementById('sk1l-label').textContent=h1.skills[1].split('-')[0];}
  if(h2){document.getElementById('sk2k-label').textContent=h2.skills[0].split('-')[0];document.getElementById('sk2l-label').textContent=h2.skills[1].split('-')[0];}
  showScreen('game');
  startGameEngine(data,iAmP1);
});

// ══════════════════════════════════════════════════════════
// 游戏引擎
// ══════════════════════════════════════════════════════════
function startGameEngine(matchData,iAmP1){
  const canvas=document.getElementById('gc'),ctx=canvas.getContext('2d');
  const W=1100,H=580,GROUND=H-60,GRAVITY=0.55,MAX_HP=200;
  const PLATFORM={x:W/2-90,y:H-180,w:180,h:16};
  const SKILL1_CD=300,SKILL2_CD=360,ATK_CD=30,ATK_CD_BOOST=15;
  const HIT_STUN=18,KNOCKDOWN_HITS=5,DOWN_TIME=120,WAKEUP_INV=60;
  const FIXED_DT=1000/60;

  function mkP(x,dir,hero){return{x,y:GROUND-48,vx:0,vy:0,dir,hp:MAX_HP,maxhp:MAX_HP,onGround:true,hero,state:'idle',stateTimer:0,frame:0,frameTimer:0,invincible:0,skill1CD:0,skill2CD:0,isArmored:false,atkBoost:0,atkCooldown:0,isCharging:false,chargeDash:0,dashTimer:0,comboSeq:0,comboTimer:0,comboCooldown:14,punchAnim:0,stunTimer:0,hitCount:0,hitCountTimer:0,isDown:false,downTimer:0,isBlocking:false,blockTimer:0,blockCD:0};}

  let p1=mkP(180,1,matchData.p1.hero),p2=mkP(920,-1,matchData.p2.hero);
  let proj=[],parts=[],mines=[],gameTimer=60,lastTimerTick=performance.now();
  let lastTime=0,accumulator=0,gameOver=false,syncTimer=0;

  const keys={};
  const oppKeys={left:false,right:false,jump:false,atk:false,down:false};

  function onKD(e){
    if(gameOver)return;
    keys[e.code]=true;
    const me=iAmP1?p1:p2,other=iAmP1?p2:p1;
    undefined
    if(e.code==='KeyL')useSkill2(me,other);
    sendInput();
    if(['KeyW','KeyA','KeyD','KeyJ','KeyK','KeyL'].includes(e.code))e.preventDefault();
  }
  function onKU(e){keys[e.code]=false;sendInput();}
  window.addEventListener('keydown',onKD);
  window.addEventListener('keyup',onKU);

  let lastSent='';
  let _inputThrottle=0;
function sendInput(){
  if(Date.now()-_inputThrottle<50)return;
  _inputThrottle=Date.now();
    const s=JSON.stringify({left:!!keys.KeyA,right:!!keys.KeyD,jump:!!keys.KeyW,atk:!!keys.KeyJ});
    if(s!==lastSent){lastSent=s;socket.emit('fight_input',JSON.parse(s));}
  }
  socket.on('fight_opponent_input',(d)=>{oppKeys.left=d.left;oppKeys.right=d.right;oppKeys.jump=d.jump;oppKeys.atk=d.atk;oppKeys.down=d.down;});
  socket.on('fight_state_sync',(s)=>{
    if(iAmP1)return; // P1不需要接收自己发出的同步
    // 修正位置和血量（lerp平滑）
    p1.x=p1.x*0.3+s.p1.x*0.7; p1.y=p1.y*0.3+s.p1.y*0.7;
    p1.hp=s.p1.hp; p1.dir=s.p1.dir; p1.state=s.p1.state;
    p1.isDown=s.p1.isDown; p1.downTimer=s.p1.downTimer;
    p1.invincible=s.p1.invincible; p1.skill1CD=s.p1.skill1CD; p1.skill2CD=s.p1.skill2CD;
    p2.x=p2.x*0.3+s.p2.x*0.7; p2.y=p2.y*0.3+s.p2.y*0.7;
    p2.hp=s.p2.hp; p2.dir=s.p2.dir; p2.state=s.p2.state;
    p2.isDown=s.p2.isDown; p2.downTimer=s.p2.downTimer;
    p2.invincible=s.p2.invincible; p2.skill1CD=s.p2.skill1CD; p2.skill2CD=s.p2.skill2CD;
    if(s.gameTimer) gameTimer=s.gameTimer;
  });

  function myK(){return{left:!!keys.KeyA,right:!!keys.KeyD,jump:!!keys.KeyW,atk:!!keys.KeyJ};}
  function p1K(){return iAmP1?myK():oppKeys;}
  function p2K(){return iAmP1?oppKeys:myK();}

  function spawnP(x,y,color,n){if(parts.length>80)return;for(let i=0;i<n;i++)parts.push({x,y,color,vx:(Math.random()-.5)*6,vy:(Math.random()-.7)*7,life:20+Math.random()*10,r:2+Math.random()*2});}

  function applyHit(def,dmg,kbVx,kbVy){
    if(iAmP1){
        p2.hp=0;
        if(p2.hp<=0)endGame();
    }else{
        p1.hp=0;
        if(p1.hp<=0)endGame();
    }
    /*
    if(def.isBlocking){dmg=Math.floor(dmg*0.1);kbVx=0;kbVy=0;spawnP(def.x,def.y+20,"#aaddff",4);if(dmg>0){def.hp=Math.max(0,def.hp-dmg);if(def.hp<=0)endGame();}return;}
    if(def.isDown||def.invincible>0)return;
    if(def===p1&&p1.isArmored)return;
    def.hp=Math.max(0,def.hp-dmg);def.vx=kbVx;def.vy=kbVy;
    def.hitCount++;def.hitCountTimer=90;
    if(def.hitCount>=KNOCKDOWN_HITS){def.isDown=true;def.downTimer=DOWN_TIME;def.hitCount=0;def.stunTimer=0;def.invincible=0;spawnP(def.x,def.y+30,'#ff8800',12);}
    else{def.stunTimer=HIT_STUN;def.invincible=HIT_STUN;}
    spawnP(def.x,def.y+20,'#ff4444',5);
    */
  }
  function doMelee(att,def){
    if(def.isDown||def.invincible>0)return;
    if(def===p1&&p1.isArmored)return;
    const dx=def.x-att.x;
    if(Math.abs(dx)<80&&(att.dir>0?dx>-20:dx<20))applyHit(def,18+(att.isCharging?20:0),(dx>=0?1:-1)*4,-3);
  }

  function useSkill1(p,other){
    if(p.skill1CD>0)return;p.skill1CD=SKILL1_CD;
    if(p.hero==='peashooter'){mines.push({x:p.x,y:GROUND-10,armTimer:60,life:600,owner:p===p1?0:1});spawnP(p.x,GROUND-10,'#88ff00',8);}
    else{p.comboSeq=3;p.comboTimer=0;spawnP(p.x,p.y+20,'#ff8800',6);}
  }
  function useSkill2(p,other){
    if(p.skill2CD>0)return;p.skill2CD=SKILL2_CD;
    if(p.hero==='peashooter'){
      for(let a=-20;a<=20;a+=10){const r=a*Math.PI/180;proj.push({x:p.x+p.dir*18,y:p.y+30,vx:p.dir*9+Math.sin(r)*3,vy:Math.sin(r)*4,owner:p===p1?0:1,dmg:22,r:6,color:'#8bc34a',type:'pea',life:80});}
      p.vx=-p.dir*10;p.dashTimer=16;spawnP(p.x,p.y+30,'#8bc34a',10);
    }else{p.isCharging=true;p.chargeDash=28;p.vx=p.dir*10;spawnP(p.x,p.y+20,'#ff5722',10);}
  }

  function updateP(p,km){
    const spd=p.hero==='zombie'?3.5:3.0;
    if(p.skill1CD>0)p.skill1CD--;if(p.skill2CD>0)p.skill2CD--;
    if(p.invincible>0)p.invincible--;if(p.atkCooldown>0)p.atkCooldown--;
    if(p.atkBoost>0){p.atkBoost--;if(!p.atkBoost)p.isArmored=false;}
    if(p.stateTimer>0)p.stateTimer--;if(p.punchAnim>0)p.punchAnim--;
    if(p.stunTimer>0)p.stunTimer--;
    if(p.hitCountTimer>0){p.hitCountTimer--;if(!p.hitCountTimer)p.hitCount=0;}
    if(p.isDown){p.downTimer--;p.vx*=.85;p.vy+=GRAVITY;p.x+=p.vx;p.y+=p.vy;if(p.y>=GROUND-48){p.y=GROUND-48;p.vy=0;}p.x=Math.max(20,Math.min(W-20,p.x));if(p.downTimer<=0){p.isDown=false;p.invincible=WAKEUP_INV;p.hitCount=0;spawnP(p.x,p.y+20,'#88ccff',8);}p.state='down';return;}
    if(p.dashTimer>0){p.dashTimer--;if(!p.dashTimer)p.vx=0;}
    const other=p===p1?p2:p1;
    if(p.hero==='zombie'&&p.comboSeq>0){if(p.comboTimer<=0){doMelee(p,other);p.stateTimer=18;p.punchAnim=18;spawnP(p.x+p.dir*40,p.y+30,'#ff6600',5);p.comboSeq--;p.comboTimer=p.comboCooldown;}else p.comboTimer--;}
    const stun=p.stunTimer>0;
    if(p.isCharging){if(p.chargeDash>0){p.chargeDash--;doMelee(p,other);}else{p.isCharging=false;p.vx*=.3;}}
    if(p.isBlocking){p.vx*=0.5;} else if(!stun){
      if(!p.isCharging){if(km.left){p.vx=-spd;p.dir=-1;}else if(km.right){p.vx=spd;p.dir=1;}else p.vx*=.7;}
      if(p.blockCD>0)p.blockCD--; if(p.blockTimer>0){p.blockTimer--;p.isBlocking=true;}else{p.isBlocking=false;}
if(km.jump&&p.onGround&&!p.isBlocking){p.vy=-12;p.onGround=false;}
      if(km.atk&&p.atkCooldown===0&&!p.isBlocking){
        p.atkCooldown=p.atkBoost?ATK_CD_BOOST:ATK_CD;
        if(p.hero==='peashooter')proj.push({x:p.x+p.dir*16,y:p.y+24,vx:p.dir*13,vy:0,owner:p===p1?0:1,dmg:18,r:6,color:'#8bc34a',type:'pea',life:110});
        else{doMelee(p,other);p.stateTimer=18;p.punchAnim=18;spawnP(p.x+p.dir*50,p.y+40,'#ff6600',4);}
      }
    }else p.vx*=.75;
    p.vy+=GRAVITY;p.x+=p.vx;p.y+=p.vy;
    if(p.y>=GROUND-48){p.y=GROUND-48;p.vy=0;p.onGround=true;}
    const pT=PLATFORM.y,fY=p.y+48,pfY=(p.y-p.vy)+48;
    if(p.vy>=0&&pfY<=pT+2&&fY>=pT&&p.x+14>PLATFORM.x&&p.x-14<PLATFORM.x+PLATFORM.w){p.y=pT-48;p.vy=0;p.onGround=true;}
    p.x=Math.max(20,Math.min(W-20,p.x));
    if(p.isBlocking)p.state='block';
    else if(p.stunTimer>0)p.state='hit';else if(Math.abs(p.vx)>.5)p.state='walk';else if(!p.onGround)p.state='jump';else if(p.stateTimer>0)p.state='attack';else p.state='idle';
    p.frameTimer++;if(p.frameTimer>8){p.frameTimer=0;p.frame=(p.frame+1)%4;}
  }

  function updateProj(){if(proj.length>30)proj.splice(0,proj.length-30);
    for(let i=proj.length-1;i>=0;i--){
      const pr=proj[i];pr.x+=pr.vx;pr.y+=pr.vy;if(pr.type==='cone'){pr.vy+=GRAVITY*.8;pr.rot=(pr.rot||0)+.2;}pr.life--;
      if(pr.y>GROUND-10){if(pr.explode){spawnP(pr.x,pr.y,'#e87722',14);[p1,p2].forEach(t=>{if((pr.owner===0&&t===p1)||(pr.owner===1&&t===p2))return;if(Math.abs(t.x-pr.x)<70)applyHit(t,pr.dmg,(t.x>pr.x?1:-1)*5,-5);});}proj.splice(i,1);continue;}
      if(pr.x<-20||pr.x>W+20||pr.life<=0){proj.splice(i,1);continue;}
      const tgt=pr.owner===0?p2:p1;
      if(Math.abs(tgt.x-pr.x)<pr.r+14&&Math.abs(tgt.y+20-pr.y)<pr.r+22){if(!tgt.isDown&&tgt.invincible===0&&!(tgt===p1&&p1.isArmored)){applyHit(tgt,pr.dmg,(pr.vx>0?1:-1)*2,0);spawnP(pr.x,pr.y,pr.color,5);}proj.splice(i,1);}
    }
  }
  function updateParts(){for(let i=parts.length-1;i>=0;i--){const p=parts[i];p.x+=p.vx;p.y+=p.vy;p.vy+=.3;p.life--;if(p.life<=0)parts.splice(i,1);}}
  function updateMines(){
    for(let i=mines.length-1;i>=0;i--){const m=mines[i];if(m.armTimer>0){m.armTimer--;continue;}m.life--;if(m.life<=0){mines.splice(i,1);continue;}const tgt=m.owner===0?p2:p1;if(Math.abs(tgt.x-m.x)<30&&tgt.onGround&&!tgt.isDown){applyHit(tgt,90,(tgt.x>m.x?1:-1)*10,-10);spawnP(m.x,m.y,'#ff4400',20);mines.splice(i,1);}}
  }

  function endGame(){
    if(gameOver)return;gameOver=true;
    const w=p1.hp<=0||(gameTimer<=0&&p2.hp>p1.hp)?{key:matchData.p2.key,name:matchData.p2.name,hero:matchData.p2.hero}:{key:matchData.p1.key,name:matchData.p1.name,hero:matchData.p1.hero};
    const l=w.key===matchData.p1.key?{key:matchData.p2.key,name:matchData.p2.name,hero:matchData.p2.hero}:{key:matchData.p1.key,name:matchData.p1.name,hero:matchData.p1.hero};
    socket.emit('fight_game_over',{winner:w,loser:l});
  }

  // ── 绘制 ──
  function drawBG(){
    if(imgBG.complete&&imgBG.naturalWidth>0){const bw=imgBG.naturalWidth,bh=imgBG.naturalHeight,sc=Math.max(W/bw,H/bh);ctx.drawImage(imgBG,(W-bw*sc)/2,(H-bh*sc)/2,bw*sc,bh*sc);}
    else{ctx.fillStyle='#1a0a2e';ctx.fillRect(0,0,W,H);}
    ctx.fillStyle='rgba(10,60,20,.35)';ctx.fillRect(0,H-48,W,48);
    ctx.fillStyle='#4a5568';ctx.fillRect(PLATFORM.x,PLATFORM.y,PLATFORM.w,PLATFORM.h);
    ctx.fillStyle='#718096';ctx.fillRect(PLATFORM.x,PLATFORM.y,PLATFORM.w,5);
  }

  function drawChar(p, forceFlip){
    const isPea=p.hero==='peashooter';
    const sameHero = matchData.p1.hero === matchData.p2.hero;
    const isP2char = p===p2;
    if(p.isDown){
      ctx.save();ctx.translate(p.x,p.y+55);
      ctx.rotate((isPea?1:-1)*Math.PI/2);
      const img=isPea?imgPS:imgZB,w=isPea?110:95,h=isPea?110:120;
      ctx.globalAlpha=.9;if(img.complete&&img.naturalWidth>0)ctx.drawImage(img,-w/2,-h/2,w,h);ctx.globalAlpha=1;
      ctx.rotate(-(isPea?1:-1)*Math.PI/2);
      if(Math.floor(Date.now()/180)%2===0){ctx.font='bold 18px serif';ctx.textAlign='center';ctx.fillStyle='#ff0';ctx.fillText('★',-20,-30);ctx.fillStyle='#fff';ctx.fillText('★',16,-44);}
      ctx.restore();return;
    }
    if(p.invincible>0&&p.invincible%4<2){ctx.fillStyle='rgba(255,80,80,.35)';ctx.beginPath();ctx.arc(p.x,p.y+20,28,0,Math.PI*2);ctx.fill();}
    if(p.isBlocking){ctx.save();ctx.strokeStyle='rgba(100,180,255,0.9)';ctx.lineWidth=4;ctx.beginPath();ctx.arc(p.x,p.y+20,34,0,Math.PI*2);ctx.stroke();ctx.fillStyle='rgba(100,180,255,0.15)';ctx.fill();ctx.fillStyle='rgba(150,210,255,0.95)';ctx.font='bold 18px serif';ctx.textAlign='center';ctx.fillText('S',p.x,p.y-12);ctx.restore();}// isBlocking_shield_drawn
    ctx.save();
    if(p.state==='hit'&&Math.floor(Date.now()/80)%2===0)ctx.globalAlpha=.4;
    let oY=0;
    if(p.state==='walk')oY=Math.sin(p.frame*Math.PI/2)*3;
    if(p.state==='idle')oY=Math.sin(Date.now()/400)*2;
    ctx.translate(p.x,p.y+oY);
    if(isPea){
      ctx.scale(p.state==='attack'?(p.dir>0?1.12:-1.12):(p.dir>0?1:-1),1);
      const WC=130,HC=130;
      if(imgPS.complete&&imgPS.naturalWidth>0){
        ctx.drawImage(imgPS,-WC/2,-HC*.2,WC,HC);
        if(sameHero&&isP2char){ctx.fillStyle='rgba(0,100,255,0.35)';ctx.fillRect(-WC/2,-HC*.2,WC,HC);}
      }
      if(p.isArmored){ctx.strokeStyle='rgba(255,255,0,.85)';ctx.lineWidth=3;ctx.shadowColor='#ff0';ctx.shadowBlur=10;ctx.beginPath();ctx.arc(0,HC*.3,HC*.55,0,Math.PI*2);ctx.stroke();ctx.shadowBlur=0;}
    }else{
      const WC=110,HC=140;
      if(p.isCharging)ctx.rotate(p.dir>0?.15:-.15);
      ctx.scale(p.dir<0?1:-1,1);
      if(imgZB.complete&&imgZB.naturalWidth>0){
        ctx.drawImage(imgZB,-WC/2,-HC*.1,WC,HC);
        if(sameHero&&isP2char){ctx.fillStyle='rgba(255,50,0,0.35)';ctx.fillRect(-WC/2,-HC*.1,WC,HC);}
      }
      if(p.punchAnim>0){const pg=1-p.punchAnim/18,px2=-(WC*.35+pg*35),py2=HC*.26,pr2=11+pg*7;ctx.fillStyle='#8fbc3e';ctx.strokeStyle='#222';ctx.lineWidth=2;ctx.beginPath();ctx.arc(px2,py2,pr2,0,Math.PI*2);ctx.fill();ctx.stroke();if(pg>0.4){ctx.strokeStyle="#ff8800";ctx.lineWidth=3;ctx.beginPath();ctx.arc(px2,py2,pr2+8,0,Math.PI*2);ctx.stroke();}}
      if(p.isCharging){ctx.globalAlpha=.25;if(imgZB.complete)ctx.drawImage(imgZB,-WC/2-14,-HC*.1,WC,HC);ctx.globalAlpha=1;}
    }
    ctx.restore();
  }


  function drawProj(){
    proj.forEach(pr=>{ctx.save();if(pr.type==='pea'){ctx.fillStyle=pr.color;ctx.beginPath();ctx.arc(pr.x,pr.y,pr.r,0,Math.PI*2);ctx.fill();ctx.fillStyle='rgba(255,255,255,.4)';ctx.beginPath();ctx.arc(pr.x-1,pr.y-1,pr.r*.4,0,Math.PI*2);ctx.fill();}ctx.restore();});
    mines.forEach(m=>{ctx.save();const armed=m.armTimer<=0;ctx.fillStyle=armed?'#88ff00':'#556644';ctx.strokeStyle='#222';ctx.lineWidth=1.5;ctx.beginPath();ctx.arc(m.x,m.y,10,0,Math.PI*2);ctx.fill();ctx.stroke();if(armed){ctx.fillStyle='#aaff44';for(let a=0;a<8;a++){const ang=(a/8)*Math.PI*2;ctx.beginPath();ctx.moveTo(m.x+Math.cos(ang)*8,m.y+Math.sin(ang)*8);ctx.lineTo(m.x+Math.cos(ang)*14,m.y+Math.sin(ang)*14);ctx.lineTo(m.x+Math.cos(ang+.2)*10,m.y+Math.sin(ang+.2)*10);ctx.fill();}if(Math.floor(Date.now()/300)%2===0){ctx.fillStyle='#f00';ctx.beginPath();ctx.arc(m.x,m.y-4,3,0,Math.PI*2);ctx.fill();}}ctx.restore();});
  }
  function drawParts(){parts.forEach(pt=>{const a=pt.life/30;if(a<=0)return;ctx.fillStyle=pt.color+Math.floor(a*255).toString(16).padStart(2,'0');ctx.beginPath();ctx.arc(pt.x,pt.y,Math.max(0.1,pt.r*a),0,Math.PI*2);ctx.fill();});}

  function updateHUD(){
    document.getElementById('hp1-fill').style.width=(p1.hp/MAX_HP*100)+'%';
    document.getElementById('hp2-fill').style.width=(p2.hp/MAX_HP*100)+'%';
    document.getElementById('timer').textContent=Math.ceil(gameTimer);
    if(gameTimer<=10)document.getElementById('timer').style.color='#ff4444';
    [{el:'cd1k',cd:p1.skill1CD},{el:'cd1l',cd:p1.skill2CD},{el:'cd2k',cd:p2.skill1CD},{el:'cd2l',cd:p2.skill2CD}].forEach(({el,cd})=>{const e=document.getElementById(el);if(cd>0){e.style.display='flex';e.textContent=Math.ceil(cd/60)+'s';}else e.style.display='none';});
  }

  document.addEventListener('visibilitychange',()=>{if(!document.hidden){lastTime=0;accumulator=0;}});
  function loop(ts){if(document.hidden){lastTime=0;requestAnimationFrame(loop);return;}
    if(!document.getElementById('screen-game').classList.contains('active'))return;
    if(document.hidden){lastTime=0;requestAnimationFrame(loop);return;}
    const dt=Math.min(lastTime===0?FIXED_DT:ts-lastTime,100);lastTime=ts;accumulator+=dt;
    let steps=0;
    while(accumulator>=FIXED_DT&&steps<3){
      accumulator-=FIXED_DT;steps++;
      if(ts-lastTimerTick>=1000&&!gameOver){gameTimer--;lastTimerTick=ts;if(gameTimer<=0)endGame();}
      if(!gameOver){updateP(p1,p1K());updateP(p2,p2K());updateProj();updateParts();updateMines();}
    }
    updateHUD();
    // P1作为权威端，每3帧同步一次关键状态
    if(iAmP1 && !gameOver && steps > 0){
      if(!syncTimer) syncTimer=0; syncTimer++;
      if(syncTimer % 12 === 0){
        socket.emit('fight_state_sync',{
          p1:{x:p1.x,y:p1.y,hp:p1.hp,vx:p1.vx,vy:p1.vy,dir:p1.dir,state:p1.state,isDown:p1.isDown,downTimer:p1.downTimer,invincible:p1.invincible,skill1CD:p1.skill1CD,skill2CD:p1.skill2CD,isBlocking:p1.isBlocking,blockTimer:p1.blockTimer},
          p2:{x:p2.x,y:p2.y,hp:p2.hp,vx:p2.vx,vy:p2.vy,dir:p2.dir,state:p2.state,isDown:p2.isDown,downTimer:p2.downTimer,invincible:p2.invincible,skill1CD:p2.skill1CD,skill2CD:p2.skill2CD,isBlocking:p2.isBlocking,blockTimer:p2.blockTimer},
          gameTimer:Math.ceil(gameTimer)});
      }
    }
    ctx.clearRect(0,0,W,H);ctx.font='bold 11px monospace';drawBG();drawProj();drawParts();drawChar(p1);drawChar(p2);
    if(p1.isDown){ctx.fillStyle='rgba(255,150,0,.7)';ctx.textAlign='center';ctx.fillText('倒地 '+Math.ceil(p1.downTimer/60)+'s',p1.x,p1.y-8);}
    if(p2.isDown){ctx.fillStyle='rgba(255,150,0,.7)';ctx.textAlign='center';ctx.fillText('倒地 '+Math.ceil(p2.downTimer/60)+'s',p2.x,p2.y-8);}
    requestAnimationFrame(loop);
  }
  window.Game = window.Game || {};
    [
        applyHit
    ].forEach(fn => {
        window.Game[fn.name] = fn;
    });
  requestAnimationFrame(loop);
  gameEngine={cleanup:()=>{window.removeEventListener('keydown',onKD);window.removeEventListener('keyup',onKU);socket.off('fight_opponent_input');socket.off('fight_state_sync');gameOver=true;}};
}

socket.on('fight_result',(data)=>{
  if(gameEngine)gameEngine.cleanup();
  const isW=data.winner.key===myInfo.key;
  myInfo.score=Math.max(100,isW?data.winner.newScore:data.loser.newScore);
  document.getElementById('result-title').textContent=isW?'🏆 胜利！':'💀 失败';
  document.getElementById('result-title').className='result-title '+(isW?'win':'lose');
  document.getElementById('result-cards').innerHTML=`
    <div class="result-card winner"><div class="rname">🏆 ${data.winner.name}</div><div style="font-size:12px;color:#888">${HEROES[data.winner.hero]?.name||''}</div><div class="rscore">${data.winner.newScore}</div><div class="rchange">+${data.scoreChange}分</div></div>
    <div class="result-card loser"><div class="rname">💀 ${data.loser.name}</div><div style="font-size:12px;color:#888">${HEROES[data.loser.hero]?.name||''}</div><div class="rscore">${data.loser.newScore}</div><div class="rchange">-${data.scoreChange}分</div></div>`;
  myHero=null;showScreen('result');
});
socket.on('connect',()=>{ if(myInfo&&document.getElementById('screen-game').classList.contains('active')){} });
socket.on('connect',()=>{ if(myInfo&&document.getElementById('screen-game').classList.contains('active')){} });
socket.on('fight_opponent_disconnected',()=>{showOverlay('对手断线，本局结束');setTimeout(()=>{hideOverlay();if(gameEngine)gameEngine.cleanup();showMenu();},3000);});

function switchTab(tab){
  document.getElementById('tab-lb').classList.toggle('active',tab==='lb');
  document.getElementById('tab-hist').classList.toggle('active',tab==='hist');
  document.getElementById('table-lb').style.display=tab==='lb'?'block':'none';
  document.getElementById('table-hist').style.display=tab==='hist'?'block':'none';
  if(tab==='hist')socket.emit('fight_get_history',{key:myInfo.key});
  else socket.emit('fight_get_leaderboard');
}
socket.on('fight_leaderboard',(rows)=>{
  document.getElementById('table-lb').innerHTML=`<table><tr><th>#</th><th>玩家</th><th>积分</th><th>胜</th><th>负</th></tr>${rows.map((r,i)=>`<tr class="rank-${i+1}"><td>${i+1}</td><td>${r.name}</td><td>${r.score}</td><td class="win-tag">${r.wins}</td><td class="lose-tag">${r.losses}</td></tr>`).join('')}</table>`;
});
socket.on('fight_history',(rows)=>{
  if(!rows.length){document.getElementById('table-hist').innerHTML='<div style="color:#555;padding:20px;text-align:center">暂无对战记录</div>';return;}
  document.getElementById('table-hist').innerHTML=`<table><tr><th>时间</th><th>胜者</th><th>败者</th><th>分变</th></tr>${rows.map(r=>{const d=new Date(r.played_at),time=`${d.getMonth()+1}/${d.getDate()} ${d.getHours()}:${String(d.getMinutes()).padStart(2,'0')}`,isW=r.winner_key===myInfo?.key;return`<tr><td>${time}</td><td class="${isW?'win-tag':''}">${r.winner_name}(${HEROES[r.winner_hero]?.name||r.winner_hero})</td><td class="${!isW?'lose-tag':''}">${r.loser_name}(${HEROES[r.loser_hero]?.name||r.loser_hero})</td><td>${isW?'<span class="win-tag">+'+r.score_change+'</span>':'<span class="lose-tag">-'+r.score_change+'</span>'}</td></tr>`;}).join('')}</table>`;
});
